import{_ as i,o as e,c as l,a4 as r}from"./chunks/framework.BhEBm8_q.js";const _=JSON.parse('{"title":"AI 대화","description":"","frontmatter":{},"headers":[],"relativePath":"12-ai-chat.md","filePath":"12-ai-chat.md"}'),t={name:"12-ai-chat.md"};function o(n,a,d,h,c,s){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="ai-대화" tabindex="-1">AI 대화 <a class="header-anchor" href="#ai-대화" aria-label="Permalink to “AI 대화”">​</a></h1><p><em>리더 AI 질문 (마법봉)</em></p><p>AI 기능은 사용자가 명시적으로 질문하거나 전송할 때만 동작하는 실험 기능입니다. 문서를 열거나 스크롤했다고 자동으로 전송하지 않습니다.</p><h2 id="사용-준비" tabindex="-1">사용 준비 <a class="header-anchor" href="#사용-준비" aria-label="Permalink to “사용 준비”">​</a></h2><p>설정의 AI 항목에서 모델 제공자(Gemini)를 켜고 API 토큰을 등록합니다.</p><ul><li>토큰은 기기의 보안 저장소에 저장되고, 앱 DB에는 &quot;토큰이 있다&quot;는 표시만 남습니다.</li><li>직업·톤앤매너 같은 기본 설정으로 답변 스타일을 맞출 수 있습니다.</li><li>설정 화면의 테스트 버튼으로 연결이 되는지 미리 확인할 수 있습니다.</li></ul><h2 id="리더에서-질문하기" tabindex="-1">리더에서 질문하기 <a class="header-anchor" href="#리더에서-질문하기" aria-label="Permalink to “리더에서 질문하기”">​</a></h2><p>AI가 활성화되면 리더 왼쪽 아래에 AI 버튼(마법봉)이 나타납니다.</p><ul><li>잠시 사용하지 않으면 약 3.5초 뒤 옅어졌다가, 화면을 다루면 다시 또렷해집니다.</li><li>버튼을 누르면 현재 화면을 캡처해 그 맥락으로 질문할 수 있습니다.</li><li>첫 답변을 받은 뒤 후속 질문을 이어서 하면 같은 화면 맥락 위에 결과가 쌓입니다.</li><li>캡처에는 AI 아이콘과 팝업 자체는 포함되지 않습니다.</li></ul><h2 id="캘린더-추출" tabindex="-1">캘린더 추출 <a class="header-anchor" href="#캘린더-추출" aria-label="Permalink to “캘린더 추출”">​</a></h2><p><code>캘린더 추출</code> 프리셋은 현재 화면에서 일정 후보를 뽑아 줍니다.</p><ol><li>현재 리더 화면을 분석해 제목·시작/종료·종일 여부·장소·설명을 후보로 제시합니다.</li><li>내용을 검토·수정합니다.</li><li>OS 기본 캘린더 작성 화면(Android·iOS)으로 넘어갑니다.</li><li>앱이 직접 저장하지 않고, 최종 저장은 사용자가 합니다.</li></ol><h2 id="대화-관리" tabindex="-1">대화 관리 <a class="header-anchor" href="#대화-관리" aria-label="Permalink to “대화 관리”">​</a></h2><p>하단 <code>AI 대화</code> 탭에서 대화 목록과 상세를 관리합니다.</p><ul><li>사용자 메시지와 AI 응답이 말풍선으로 구분됩니다.</li><li>Markdown·코드 응답을 보기 좋게 표시하고, 길게 눌러 선택·복사할 수 있습니다.</li><li>대화를 내보내거나, 선택 삭제로 정리할 수 있습니다.</li></ul><h2 id="개인정보" tabindex="-1">개인정보 <a class="header-anchor" href="#개인정보" aria-label="Permalink to “개인정보”">​</a></h2><p>외부 AI 서비스로 보내는 화면 캡처와 질문은 사용자의 명시적 동작 이후에만 전송됩니다. 보낼 내용은 사용자가 의도한 캡처와 질문으로 한정되며, 원본 문서 전체나 전체 색인을 자동으로 올리지 않습니다.</p>',17)])])}const m=i(t,[["render",o]]);export{_ as __pageData,m as default};
